import { describe, expect, it } from '@a0n/gnosis/test';
import {
  TAURI_EDGE_FLOW_FIN,
  buildDefaultTauriEdgeCapabilityPolicy,
  buildTauriEdgeArtifactId,
  buildTauriEdgeD1Schema,
  buildTauriEdgeRequiredUcanCapabilities,
  computeTauriEdgeManifestDigest,
  decodeTauriEdgeFlowFrame,
  encodeTauriEdgeFlowFrame,
  resolveTauriEdgeD1TableNames,
  type TauriEdgeArtifactManifest,
} from './tauri-edge';

describe('tauri-edge contract helpers', () => {
  it('round-trips flowframe-encoded fragment bytes', () => {
    const payload = new TextEncoder().encode('tauri-edge');
    const encoded = encodeTauriEdgeFlowFrame({
      streamId: 7,
      sequence: 3,
      flags: TAURI_EDGE_FLOW_FIN,
      payload,
    });
    const decoded = decodeTauriEdgeFlowFrame(encoded, { budgetR: 54, initialV: 0 });

    expect(decoded.streamId).toBe(7);
    expect(decoded.sequence).toBe(3);
    expect(decoded.flags).toBe(TAURI_EDGE_FLOW_FIN);
    expect(Buffer.from(decoded.payload).toString('utf8')).toBe('tauri-edge');
  });

  it('builds deterministic manifest digests and artifact ids', () => {
    const baseManifest: Omit<TauriEdgeArtifactManifest, 'manifestDigest'> = {
      version: 1,
      runtimeTarget: 'tauri-edge',
      artifactId: 'tauri-edge-temp',
      application: {
        name: 'fractal-iam',
        version: '0.1.0',
        configPath: 'src-tauri/tauri.conf.json',
      },
      bundleDigest: 'bundle-digest-1',
      frontendDigest: 'frontend-digest-1',
      guestDigest: 'guest-digest-1',
      capabilityDigest: 'capability-digest-1',
      ucanAudience: 'aeon://tauri-edge/fractal-iam',
      ucanRequiredCaps: ['tauri-edge/artifact.hydrate aeon://artifact/x'],
      snapshotCompatibility: 'reconstructable-v1',
      entrypoints: {
        frontend: 'index.html',
        guestWasm: 'guest.wasm',
      },
      capabilityPolicy: buildDefaultTauriEdgeCapabilityPolicy({
        hasGuestWasm: true,
      }),
      fragments: [],
      createdAt: '2026-03-26T12:00:00.000Z',
    };

    const left = computeTauriEdgeManifestDigest(baseManifest);
    const right = computeTauriEdgeManifestDigest(baseManifest);
    expect(left).toBe(right);
    expect(
      buildTauriEdgeArtifactId({
        applicationName: 'fractal-iam',
        version: '0.1.0',
        bundleDigest: 'bundle-digest-1',
        capabilityDigest: 'capability-digest-1',
      })
    ).toMatch(/^tauri-edge-/);
  });

  it('declares the default D1 schema and UCAN scopes', () => {
    const tables = resolveTauriEdgeD1TableNames('tauri_edge_demo');
    const schema = buildTauriEdgeD1Schema(tables);

    expect(schema).toHaveLength(3);
    expect(schema[0]).toContain(tables.artifacts);
    expect(schema[1]).toContain(tables.fragments);
    expect(schema[2]).toContain(tables.sessions);
    expect(buildTauriEdgeRequiredUcanCapabilities('artifact-123')).toEqual([
      'tauri-edge/artifact.hydrate aeon://artifact/artifact-123',
      'tauri-edge/fragment.read aeon://artifact/artifact-123',
      'tauri-edge/session.resume aeon://artifact/artifact-123',
      'tauri-edge/invoke aeon://artifact/artifact-123',
      'tauri-edge/materialize aeon://artifact/artifact-123',
    ]);
  });
});
